import sys

def main():
    N, S, M, L = map(int, sys.stdin.readline().split())
    min_cost = float('inf')

    # Try all combinations of 6, 8, 12 packs that give at least N eggs
    for a in range(N // 6 + 2):  # +2 to ensure we cover enough
        for b in range(N // 8 + 2):
            for c in range(N // 12 + 2):
                total_eggs = 6 * a + 8 * b + 12 * c
                if total_eggs >= N:
                    cost = a * S + b * M + c * L
                    if cost < min_cost:
                        min_cost = cost

    print(min_cost)

if __name__ == "__main__":
    main()
